mapper.select:
SELECT q.id, q.heritage_id, h.name AS heritage_name, q.title, q.content, q.correct_answer, q.explanation, q.source, q.difficulty, q.created_at FROM quiz q JOIN heritage h ON q.heritage_id = h.id WHERE q.heritage_id IN
#{heritageId}
ORDER BY q.source = 'PAST_EXAM' DESC, q.id DESC

SELECT id, quiz_id, content, is_correct AS correct FROM quiz_choices WHERE quiz_id IN
#{quizId}
ORDER BY id

SELECT id, quiz_id, content, is_correct AS correct
FROM quiz_choices
WHERE id = #{choiceId}

SELECT id, quiz_session_id, selected_choice_id, is_correct AS correct, answered_at
FROM quiz_results
WHERE quiz_session_id = #{sessionId}

mapper.update:
UPDATE quiz_sessions
SET status = #{status}
WHERE id = #{sessionId}
